import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limit input length to prevent buffer overflow
        String safeInput = input.substring(0, Math.min(input.length(), 10));

        char[] buffer = new char[10];
        safeInput.getChars(0, safeInput.length(), buffer, 0); // No buffer overflow

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
